        items = inventory_data.get("objects", [])
        logger.info(f"📦 Inventory received: {len(items)} items")

        if not items:
            logger.info("💤 No items to sell.")
            return

        # 2. Analyze Items & Prepare Batch (Concurrency via TaskGroup)
        offers_batch = []

        # Python 3.11+ TaskGroup
        if hasattr(asyncio, "TaskGroup"):
            async with asyncio.TaskGroup() as tg:
                for item in items:
                    tg.create_task(process_item(client, item, offers_batch))
        else:
            # Fallback for older python
            tasks = [process_item(client, item, offers_batch) for item in items]
            await asyncio.gather(*tasks)

        # 3. Execute Batch Offer
        if offers_batch:
            logger.info(f"⚡ Executing Batch Offer ({len(offers_batch)} items)...")

            # Using v2 batch endpoint? No, DMarket has /exchange/v1/offers-batch-create usually
            # But let's check docs/auth.py. Usually it's POST /exchange/v1/offers
            # Actually, standard DMarket API for creating offers is POST /exchange/v1/offers
            # Batch: POST /exchange/v1/offers-batch-create

            payload = {"offers": offers_batch}

            try:
                response = await client.request("POST", "/exchange/v1/offers-batch-create", body=payload, sign=True)

                # Check response
                # Success format: {"result": [{"offerId": "...", "assetId": "..."}]}
                results = response.get("result", [])

                if results:
                    for res in results:
                        if res.get("successful"):
                            logger.info(f"✅ SOLD! Offer ID: {res.get('offerId')} | Asset: {res.get('assetId')}")
                        else:
                             logger.error(f"❌ Failed: {res.get('error')}")
                else:
                    logger.warning(f"⚠️ API Response: {response}")

            except Exception as e:
                logger.error(f"❌ Batch Transaction Failed: {e}")
        else:
            logger.info("💤 No suitable offers generated.")

